const OPENAI_API_KEY = "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";

export async function generateBlog(title) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "Write a high-quality blog article (300-500 words). Use simple language and good structure.",
          },
          {
            role: "user",
            content: `Write a blog about: ${title}`,
          },
        ],
      }),
    });

    const data = await res.json();

    if (!res.ok) {
      console.error(data);
      throw new Error("API failed");
    }

    return data.choices?.[0]?.message?.content || "No content generated.";
  } catch (err) {
    console.error("AI ERROR:", err);

    // fallback so UI never breaks
    return `
${title}

This is a fallback article because AI request failed.

Please check your API key or internet connection.
    `;
  }
}
